        x = 0.5 * (x + x.conj().transpose(-2, -1))
        return torch.linalg.eigh(x, UPLO=uplo)

    def func_grad_w(x, uplo):
        return func(x, uplo)[0]

    def func_grad_v(x, uplo):
        # gauge invariant loss function
        return abs(func(x, uplo)[1])

